```{.r .cell-code  code-fold="true"}
predictors <- c("augMean", "febRange", "febSD", "augSD", "annMean")

models <- map(predictors, ~ lm(as.formula(paste("Y ~", .x)),
                               data = sw_ectz))

plts1 <- map(predictors, function(predictor) {
  ggplot(sw_ectz, aes(x = .data[[predictor]], y = Y)) +
    geom_point(shape = 1, colour = "dodgerblue4") +
    geom_smooth(method = "lm", col = "magenta", fill = "pink") +
    labs(title = paste("Y vs", predictor),
         x = predictor,
         y = "Y") +
    theme_grey()
})

ggpubr::ggarrange(plotlist = plts1, ncol = 2,
                  nrow = 3, labels = "AUTO")
```

::: {.cell-output-display}
![Simple linear regressions fitted separately for five candidate climate predictors against mean Sørensen dissimilarity (`Y`) in the East Coast Transition Zone.](14-multiple-regression-and-model-specification_files/figure-html/fig-seaweed-slr-1.svg){#fig-seaweed-slr}
:::
:::


@fig-seaweed-slr shows that each predictor relates approximately linearly and positively to `Y` when examined alone. To make the strength of each marginal relationship precise, I extract the slope, its standard error, the coefficient of determination, and the overall model *p*-value from each fitted model and assemble them into @tbl-slr-fits.


::: {#tbl-slr-fits .cell tbl-cap='Summary statistics for the five simple linear regressions of mean Sørensen dissimilarity (`Y`) against individual climate predictors in the East Coast Transition Zone. Slope and SE are the partial coefficient and its standard error. *R*² is the coefficient of determination; *p* is the overall model *p*-value from the *F*-test against the intercept-only null.'}

```{.r .cell-code  code-fold="true" code-summary="Show code"}
fmt_pval <- function(p) {
  case_when(
    p < 0.001 ~ "< 0.001",
    p < 0.01  ~ paste0("= ", formatC(p, digits = 3, format = "f")),
    p < 0.05  ~ paste0("= ", formatC(p, digits = 3, format = "f")),
    TRUE      ~ paste0("= ", formatC(p, digits = 3, format = "f"))
  )
}

slr_table <- map2_dfr(predictors, models, function(pred, mod) {
  tidy_mod   <- tidy(mod)
  glance_mod <- glance(mod)
  tibble(
    Predictor = pred,
    Slope     = tidy_mod$estimate[2],
    SE        = tidy_mod$std.error[2],
    `R²`      = glance_mod$r.squared,
    `F`       = glance_mod$statistic,
    `p`       = fmt_pval(glance_mod$p.value)
  )
})

slr_table |>
  gt() |>
  fmt_number(columns = c(Slope, SE, `R²`), decimals = 3) |>
  fmt_number(columns = `F`, decimals = 2)
```

